import { Row } from "react-bootstrap";
import Accordion from "react-bootstrap/Accordion";

function QADropdown({ data }) {
  return (  
    <Row>
      <Accordion>
        <Accordion.Item eventKey="0">
          <Accordion.Header>
            <div className="m-auto">السؤال الأول</div>
          </Accordion.Header>

          <Accordion.Body>
            <div className="px-3 d-inline">الإجابة الأولى</div>
              <button className="btn-color">مسح السؤال</button>
          </Accordion.Body>
          <Accordion.Body>
            <div className="px-3 d-inline">الإجابة الثانية</div>

              <button className="btn-color">مسح السؤال</button>
            </Accordion.Body>

        </Accordion.Item>
      </Accordion>
    </Row>
  );
}

export default QADropdown;
